package com.wjx871.population.cancellation;import com.wjx871.population.common.ApiResponse;import java.time.LocalDateTime;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/household-archives") @RequiredArgsConstructor public class HouseholdArchiveController {private final CancellationService service;@GetMapping@PreAuthorize("hasAuthority('cancellation:archive:view')")public ApiResponse<Page<HouseholdArchive>> search(@RequestParam(required=false)String householdNo,@RequestParam(required=false)String headPersonName,@RequestParam(required=false)String regionCode,@RequestParam(required=false)String reasonCode,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME)LocalDateTime archivedFrom,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME)LocalDateTime archivedTo,Pageable p){return ApiResponse.ok(service.archives(householdNo,headPersonName,regionCode,reasonCode,archivedFrom,archivedTo,p));}@GetMapping("/{id}")@PreAuthorize("hasAuthority('cancellation:archive:view')")public ApiResponse<HouseholdArchive> get(@PathVariable Long id){return ApiResponse.ok(service.archive(id));}}
